patch:
--- a/multiplexer.v
+++ b/multiplexer.v
@@ -10,7 +10,7 @@
   output [15:0] mux_out
 );

-  always @(sel) begin
+  always @(*) begin
     case (sel)
       2'b00: mux_out = in0;
       2'b01: mux_out = in1;

before_code:
module mux_4to1_16bit (
  input [15:0] in0,
  input [15:0] in1,
  input [15:0] in2,
  input [15:0] in3,
  input [1:0] sel,
  output [15:0] mux_out
);

  always @(sel) begin
    case (sel)
      2'b00: mux_out = in0;
      2'b01: mux_out = in1;
      2'b10: mux_out = in2;
      2'b11: mux_out = in3;
    endcase
  end

endmodule

after_code:
module mux_4to1_16bit (
  input [15:0] in0,
  input [15:0] in1,
  input [15:0] in2,
  input [15:0] in3,
  input [1:0] sel,
  output [15:0] mux_out
);

  always @(*) begin
    case (sel)
      2'b00: mux_out = in0;
      2'b01: mux_out = in1;
      2'b10: mux_out = in2;
      2'b11: mux_out = in3;
    endcase
  end

endmodule
